import com.mongodb.client.MongoClients;
import com.mongodb.client.MongoCollection;
import com.mongodb.client.MongoDatabase;
import org.bson.Document;

public class GeoPolygonQuery {
        public static void main( String[] args ) {
                Document agg = new Document( "$search",
                new Document( "index", "<INDEX-NAME>")
                .append("compound",
                    new Document("must", Arrays.asList(new Document("geoWithin", 
                    new Document("geometry", 
                        new Document("type", "Polygon")
                            .append("coordinates", Arrays.asList(Arrays.asList(Arrays.asList(-161.323242d, 22.512557d), Arrays.asList(-152.446289d, 22.065278d), Arrays.asList(-156.09375d, 17.811456d), Arrays.asList(-161.323242d, 22.512557d)))))
                            .append("path", "address.location"))))
                .append("should", Arrays.asList(new Document("text", 
                    new Document("path", "property_type")
                        .append("query", "Condominium"))))));

                String uri = "<connection-string>";

                try (MongoClient mongoClient = MongoClients.create(uri)) {
                        MongoDatabase database = mongoClient.getDatabase("sample_airbnb");
                        MongoCollection<Document> collection = database.getCollection("listingsAndReviews");

                        collection.aggregate(Arrays.asList(agg, 
                            limit(10), 
                            project(fields(excludeId(), include("name", "address", "property_type"), computed("score", new Document("$meta", "searchScore"))))))
                            .forEach(doc -> System.out.println(doc.toJson() + "\n"));    
                }
        }
}

import com.mongodb.client.model.Aggregates.limit
import com.mongodb.client.model.Aggregates.project
import com.mongodb.client.model.Projections.*
import com.mongodb.kotlin.client.coroutine.MongoClient
import kotlinx.coroutines.runBlocking
import org.bson.Document

fun main() {
    // connect to your Atlas cluster
    val uri = "<connection-string>"
    val mongoClient = MongoClient.create(uri)

    // set namespace
    val database = mongoClient.getDatabase("sample_airbnb")
    val collection = database.getCollection<Document>("listingsAndReviews")

    runBlocking {
        // define pipeline
        val agg = Document(
            "\$search",
            Document("index", "<INDEX-NAME>")
                .append(
                    "compound",
                    Document(
                        "must", listOf(
                            Document(
                                "geoWithin",
                                Document(
                                    "geometry",
                                    Document("type", "Polygon")
                                        .append(
                                            "coordinates",
                                            listOf(
                                                listOf(
                                                    listOf(-161.323242, 22.512557),
                                                    listOf(-152.446289, 22.065278),
                                                    listOf(-156.09375, 17.811456),
                                                    listOf(-161.323242, 22.512557)
                                                )
                                            )
                                        )
                                )
                                    .append("path", "address.location")
                            )
                        )
                    )
                        .append(
                            "should", listOf(
                                Document(
                                    "text",
                                    Document("path", "property_type")
                                        .append("query", "Condominium")
                                )
                            )
                        )
                )
        )

        // run pipeline and print results
        val resultsFlow = collection.aggregate<Document>(
            listOf(
                agg,
                limit(10),
                project(fields(
                    excludeId(),
                    include("name", "address", "property_type"),
                    computed("score", Document("\$meta", "searchScore"))
                ))
            )
        )
        resultsFlow.collect { println(it) }
    }
    mongoClient.close()
}

